// Custom 3D Physics Tech Stack
// Mimics React Three Fiber + Rapier physics using regular Three.js + Cannon.js

document.addEventListener("DOMContentLoaded", () => {
  const container = document.getElementById("tech-canvas-container");
  if (!container) return;

  // Wait for Three.js and Cannon.js to load via CDN
  const checkDependencies = setInterval(() => {
    if (typeof THREE !== 'undefined' && typeof CANNON !== 'undefined') {
      clearInterval(checkDependencies);
      initPhysicsScene(container);
    }
  }, 100);
});

function initPhysicsScene(container) {
  // Scene setup
  const scene = new THREE.Scene();
  // Adjust camera to look orthographic-ish but keep perspective
  const camera = new THREE.PerspectiveCamera(32.5, container.clientWidth / container.clientHeight, 1, 100);
  camera.position.set(0, 0, 20);

  const renderer = new THREE.WebGLRenderer({ alpha: true, antialias: true });
  renderer.setSize(container.clientWidth, container.clientHeight);
  renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
  renderer.shadowMap.enabled = true;
  renderer.shadowMap.type = THREE.PCFSoftShadowMap;
  renderer.toneMapping = THREE.ACESFilmicToneMapping;
  renderer.toneMappingExposure = 1.5;
  container.appendChild(renderer.domElement);

  // Lights
  scene.add(new THREE.AmbientLight(0xffffff, 1.0));
  
  const directionalLight = new THREE.DirectionalLight(0xffffff, 2);
  directionalLight.position.set(0, 5, -4);
  scene.add(directionalLight);

  const spotLight = new THREE.SpotLight(0xffffff, 3);
  spotLight.position.set(20, 20, 25);
  spotLight.angle = 0.2;
  spotLight.penumbra = 1;
  spotLight.castShadow = true;
  spotLight.shadow.mapSize.width = 512;
  spotLight.shadow.mapSize.height = 512;
  scene.add(spotLight);

  // Physics World
  const world = new CANNON.World();
  world.gravity.set(0, -6, 0); // Floaty gravity
  world.broadphase = new CANNON.SAPBroadphase(world);
  world.solver.iterations = 10;

  // Invisible generic bounds so they don't fall off-screen entirely
  const wallMaterial = new CANNON.Material();
  const groundBody = new CANNON.Body({ mass: 0, material: wallMaterial });
  groundBody.addShape(new CANNON.Plane());
  groundBody.quaternion.setFromEuler(-Math.PI / 2, 0, 0);
  groundBody.position.set(0, -12, 0); // Drop floor below visible area slightly
  world.addBody(groundBody);
  
  const ceilBody = new CANNON.Body({ mass: 0, material: wallMaterial });
  ceilBody.addShape(new CANNON.Plane());
  ceilBody.quaternion.setFromEuler(Math.PI / 2, 0, 0);
  ceilBody.position.set(0, 15, 0);
  world.addBody(ceilBody);

  const leftBody = new CANNON.Body({ mass: 0, material: wallMaterial });
  leftBody.addShape(new CANNON.Plane());
  leftBody.quaternion.setFromEuler(0, Math.PI / 2, 0);
  leftBody.position.set(-15, 0, 0);
  world.addBody(leftBody);

  const rightBody = new CANNON.Body({ mass: 0, material: wallMaterial });
  rightBody.addShape(new CANNON.Plane());
  rightBody.quaternion.setFromEuler(0, -Math.PI / 2, 0);
  rightBody.position.set(15, 0, 0);
  world.addBody(rightBody);
  
  const backBody = new CANNON.Body({ mass: 0, material: wallMaterial });
  backBody.addShape(new CANNON.Plane());
  backBody.position.set(0, 0, -2);
  world.addBody(backBody);

  const frontBody = new CANNON.Body({ mass: 0, material: wallMaterial });
  frontBody.addShape(new CANNON.Plane());
  frontBody.quaternion.setFromEuler(0, Math.PI, 0);
  frontBody.position.set(0, 0, 5);
  world.addBody(frontBody);

  // Textures matching the react project
  const textureLoader = new THREE.TextureLoader();
  const imageUrls = [
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,",
    "data:image/webp;base64,"
  ];
  
  const materials = imageUrls.map(url => {
    const tex = textureLoader.load(url);
    tex.wrapS = THREE.RepeatWrapping;
    tex.wrapT = THREE.RepeatWrapping;
    return new THREE.MeshPhysicalMaterial({
      map: tex, emissive: 0xffffff, emissiveMap: tex, emissiveIntensity: 0.3,
      metalness: 0.5, roughness: 1, clearcoat: 0.1
    });
  });

  const sphereGeo = new THREE.SphereGeometry(1, 32, 32);
  const physicsMaterial = new CANNON.Material();
  const contactMaterial = new CANNON.ContactMaterial(physicsMaterial, wallMaterial, {
    friction: 0.2, restitution: 0.6, bounce: 0.5
  });
  world.addContactMaterial(contactMaterial);

  const spheres = [];
  const TOTAL_SPHERES = 25;
  const scales = [0.7, 1, 0.8, 1, 1];

  for (let i = 0; i < TOTAL_SPHERES; i++) {
    const scale = scales[Math.floor(Math.random() * scales.length)];
    const mat = materials[Math.floor(Math.random() * materials.length)];
    
    // Three.js Mesh
    const mesh = new THREE.Mesh(sphereGeo, mat);
    mesh.scale.set(scale, scale, scale);
    mesh.castShadow = true;
    mesh.receiveShadow = true;
    scene.add(mesh);

    // Cannon.js Body
    const r = (spread) => (Math.random() - 0.5) * spread;
    const body = new CANNON.Body({
      mass: scale * 2,
      position: new CANNON.Vec3(r(20), r(20) + 15, r(10)),
      shape: new CANNON.Sphere(scale),
      material: physicsMaterial,
      linearDamping: 0.75, angularDamping: 0.15
    });
    
    // Add random torque for some initial spin
    body.torque.set(r(50), r(50), r(50));
    world.addBody(body);

    spheres.push({ mesh, body, scale });
  }

  // Pointer kinematic body
  const pointerBody = new CANNON.Body({
    mass: 0, type: CANNON.Body.KINEMATIC,
    position: new CANNON.Vec3(0, -999, 0),
    shape: new CANNON.Sphere(2)
  });
  world.addBody(pointerBody);

  // Mouse tracking
  const mouse = new THREE.Vector2();
  const vec = new THREE.Vector3();
  const targetVec = new CANNON.Vec3(0, -999, 0);

  window.addEventListener('mousemove', (e) => {
    const rect = container.getBoundingClientRect();
    mouse.x = ((e.clientX - rect.left) / rect.width) * 2 - 1;
    mouse.y = -((e.clientY - rect.top) / rect.height) * 2 + 1;
  });

  // Handle Resize
  window.addEventListener('resize', () => {
    camera.aspect = container.clientWidth / container.clientHeight;
    camera.updateProjectionMatrix();
    renderer.setSize(container.clientWidth, container.clientHeight);
  });

  // Animation Loop
  const clock = new THREE.Clock();
  
  // Track if we are active
  let isActive = false;
  window.addEventListener('scroll', () => {
    const rect = container.getBoundingClientRect();
    if (rect.top < window.innerHeight && rect.bottom > 0) {
      isActive = true;
    } else {
      isActive = false;
    }
  });

  function animate() {
    requestAnimationFrame(animate);
    const delta = Math.min(clock.getDelta(), 0.1);

    if (isActive) {
      // Update Physics
      world.step(1/60, delta, 3);
      
      // Update Pointer position
      vec.set(mouse.x, mouse.y, 0).unproject(camera);
      vec.sub(camera.position).normalize();
      const distance = -camera.position.z / vec.z;
      const pos = camera.position.clone().add(vec.multiplyScalar(distance));
      
      targetVec.x += (pos.x - targetVec.x) * 0.2;
      targetVec.y += (pos.y - targetVec.y) * 0.2;
      pointerBody.position.copy(targetVec);

      // Add a slight upwards/forward force to prevent clumping at the bottom
      spheres.forEach(({ mesh, body, scale }) => {
        const force = new CANNON.Vec3(
          (Math.random() - 0.5) * 5 * scale,
          Math.random() * 8 * scale, 
          Math.random() * 2 * scale
        );
        if(body.position.y < -8) { // If it gets too low, pop it back up like a popcorn machine
            body.applyImpulse(new CANNON.Vec3((Math.random()-0.5)*15, 30*scale, (Math.random()-0.5)*15), body.position);
        }
        
        // Sync mesh to body
        mesh.position.copy(body.position);
        mesh.quaternion.copy(body.quaternion);
      });
    }

    renderer.render(scene, camera);
  }
  animate();
}
